UPDATE `l9n7b_product_lang` SET description='<p>Περούκα μαύρη μακριά μέχρι τη μέση στο στιλ της Μορτίσια Άνταμς</p>', description_short=NULL, name='Μορτίσια Μακριά Μαύρη περούκα', link_rewrite='morticia-addams-wig' WHERE id_product=20 AND id_shop=1 AND id_lang=2;
UPDATE `l9n7b_product_lang` SET description='<p></p>\n<hr />\n<p>Unleash the warrior within with our Xena wig, a stunning tribute to the iconic heroine. Each strand of this long, black, straight wig with a chic fringe is meticulously crafted in our quaint manufactory nestled in the heart of Athens, Greece. Beyond its striking aesthetics, this wig boasts exceptional quality and durability, promising years of captivating looks.</p>\n<p>Designed with versatility in mind, the Xena features a deep wig base that effortlessly accommodates a wide range of head sizes, from 42 cm to 63 cm in circumference, ensuring a comfortable fit for everyone. The resilience of this piece allows for regular washing and combing, enabling you to refresh and restyle it as often as desired without compromising its integrity.</p>\n<p>Invest in a piece of artisanal craftsmanship with our Xena wig, and enjoy a timeless accessory that continues to impress, wear after wear</p>\n<p></p>', description_short='<hr />\n<p>Unleash the warrior within with our Xena wig, a stunning tribute to the iconic heroine.</p>\n<p></p>', name='Xena Black Wig', link_rewrite='xena-black-long-wig' WHERE id_product=21 AND id_shop=1 AND id_lang=1;
UPDATE `l9n7b_product_lang` SET description='<p>Περούκα ίσια μακριά με αφέλεια.</p>\n<p>Σχεδιασμένη με γνώμονα την ευελιξία, η Xena διαθέτει μια βαθιά ελαστική βάση που προσαρμόζεται αβίαστα σε ένα ευρύ φάσμα μεγεθών κεφαλής, από 42 cm έως 63 cm σε περίμετρο, εξασφαλίζοντας άνετη εφαρμογή για όλους. Η ανθεκτικότητά της επιτρέπει το τακτικό λούσιμο και χτένισμα, δίνοντάς  σας τη δυνατότητα να το φρεσκάρετε όσο συχνά επιθυμείτε χωρίς να φθείρεται.</p>\n<p>Επενδύστε σε ένα κομμάτι χειροποίητο, την  περούκα Xena και απολαύστε ένα διαχρονικό αξεσουάρ που συνεχίζει να εντυπωσιάζει για χρόνια.</p>\n<p></p>\n<p></p>', description_short='<p>Απελευθερώστε την πολεμίστρια μέσα σας με την περούκα Xena, έναν εκπληκτικό φόρο τιμής στην εμβληματική ηρωίδα.</p>\n<p></p>', name='Περούκα Σίσσυ (Xena) Μαύρη', link_rewrite='xena-black-wig' WHERE id_product=21 AND id_shop=1 AND id_lang=2;
UPDATE `l9n7b_product_lang` SET description='<p></p>\n<p>Discover the charm of our Xena wig, a beautiful long, below-shoulder-length blonde piece with a stylish fringe, handcrafted in our small workshop in Athens, Greece. This wig is designed with quality in mind, ensuring it lasts for years to come.</p>\n<p>Featuring a deep wig base, it comfortably fits a range of head sizes from 42 cm to 63 cm, making it a versatile choice for many. It\'s built to withstand multiple uses, allowing you to wash, comb, and wear it repeatedly without losing its appeal.</p>\n<p>Our Xena wig is a practical and elegant choice, offering both durability and a touch of style for everyday wear or special occasions.</p>\n<p></p>', description_short='<p>Long blonde wig with fringe</p>', name='Xena Blonde Long Wig', link_rewrite='xena-blonde-wig' WHERE id_product=22 AND id_shop=1 AND id_lang=1;
UPDATE `l9n7b_product_lang` SET description='<p>Ανακαλύψτε τη γοητεία της περούκας μας Σίσσυ μια όμορφη μακριά, κάτω από τους ώμους, ξανθιά περούκα με κομψή φράντζα, χειροποίητη φτιαγμένη στο εργαστήριό μας στην Αθήνα. Αυτή η περούκα έχει σχεδιαστεί με γνώμονα την ποιότητα, εξασφαλίζοντας ότι θα διαρκέσει για πολλά χρόνια.</p>\n<p>Διαθέτοντας μια βαθιά βάση περούκας, ταιριάζει άνετα στους περισσότερους ανθρώπους. Είναι κατάλληλη για μεγέθη κεφαλής από 42 cm έως 63 cm, καθιστώντας την μια ευέλικτη επιλογή για πολλούς. Είναι κατασκευασμένο για να αντέχει σε πολλαπλές χρήσεις, επιτρέποντάς σας να τη λούζετε, να τη χτενίζετε και να τη φοράτε επανειλημμένα χωρίς να χάνει το φρεσκάδα της.</p>\n<p>Η περούκα Σίσσυ  είναι μια πρακτική και κομψή επιλογή, προσφέροντας τόσο ανθεκτικότητα όσο και μια πινελιά στυλ για χρήση σε πάρτι, φωτογραφίσεις και θεατρικές παραστάσεις</p>\n<p></p>\n<p></p>', description_short='<p>Περούκα ίσια μακριά με αφέλεια.</p>', name='Περούκα Σίσσυ Ξανθιά', link_rewrite='xena-blonde-wig' WHERE id_product=22 AND id_shop=1 AND id_lang=2;
