UPDATE `l9n7b_product_lang` SET description='<p>Showcase the charm and aristocratic elegance of Dalia from the beloved TV series <em>Para Pente</em>. This blonde, wavy wig exudes style and sophistication, making it perfect for theatrical performances, cosplay, and, of course, costume parties.</p>\n<p>Crafted in Greece, it features an elastic base that fits head circumferences from 48 cm to 62.5 cm, ensuring comfort and a secure fit.</p>\n<p></p>', description_short='<p>Blonde, wavy wig inspired by Dalia from the beloved series "Para Pente," perfect for theater, cosplay, and costume parties. Made in Greece with an elastic base fitting head circumferences 48-62.5 cm.</p>', name='DALIA blonde wavy wig', link_rewrite='dalia-blonde-wig' WHERE id_product=138 AND id_shop=1 AND id_lang=1;
UPDATE `l9n7b_product_lang` SET description='<h3><strong> </strong></h3>\n<p>Αναδείξτε τη γοητεία και την αριστοκρατική φινέτσα της Ντάλιας από την  αγαπημένη τηλεοπτική σειράς Παρά Πέντε. Αυτή η ξανθιά, κυματιστή περούκα αποπνέει στυλ και κομψότητα. Είναι ιδανική για θεατρικές παραστάσεις, cosplay και φυσικά πάρτι μασκέ.</p>\n<p>Κατασκεύαζεται στην Ελλάδα, έχει ελαστική βάση που ταιριάζει σε περιφέρειες κεφαλιού από 48 cm έως 62,5 cm</p>\n<hr />\n<p></p>', description_short='<p>Ξανθιά, κυματιστή περούκα εμπνευσμένη από τη Ντάλια του Παρά Πέντε, ιδανική για θέατρο, cosplay και πάρτι μασκέ. Κατασκευάζεται στην Ελλάδα</p>', name='Νταλια περούκα μακριά σπαστή ξανθιά', link_rewrite='dalia-perouka' WHERE id_product=138 AND id_shop=1 AND id_lang=2;
