UPDATE `l9n7b_product_lang` SET description='<p><strong>Step back into the swinging 1960s with our Suzan Blonde Wig!</strong></p>\n<p><strong> This eye-catching blonde wig, adorned with a vibrant yellow ribbon, encapsulates the era\'s high-fashion and exuberance.</strong></p>\n<p><strong> Ideal for costume parties, themed events, or just a fun night out, this high-quality synthetic wig is built for comfort and lasting style. </strong></p>\n<p><strong>Get ready to turn heads and bring retro charm to your modern looks with our must-have Suzan Blonde Wig!</strong></p>', description_short='<p><strong>This eye-catching blonde wig, adorned with a vibrant yellow ribbon, encapsulates the era\'s high-fashion and exuberance.</strong></p>', name='SUZAN BLONDE LADIES PATSY WIG', link_rewrite='SUZAN-BLONDE-WIG', meta_description='1960S TALL BLONDE WIG' WHERE id_product=173 AND id_shop=1 AND id_lang=1;
