UPDATE `l9n7b_product_lang` SET description='<p>Step back into the iconic era of the 1980s with our meticulously crafted mullet wig for men, where style meets the quintessence of vintage charm. This premium-quality wig captures the essence of the decade with its unmistakable silhouette, blending the party-at-the-back flair with a dash of business-at-the-front sophistication. Designed with a generous base, this wig effortlessly accommodates your natural hair, ensuring a seamless and natural look. Its superior elasticity guarantees a snug and comfortable fit, allowing you to move, dance, and groove with confidence and ease. Whether you\'re channeling your inner rock star or completing your costume with authentic \'80s panache, our mullet wig is the ultimate accessory for making a bold statement.</p>', description_short='<p>Step back into the iconic era of the 1980s with our meticulously crafted mullet wig for men, where style meets the quintessence of vintage charm</p>', name='Mullet 1980\'S MEN\'S HAIR', link_rewrite='80-s-men-s-hair', meta_title='XAITH' WHERE id_product=231 AND id_shop=1 AND id_lang=1;
