UPDATE `l9n7b_product_lang` SET description='<p>This wig is made to resemble Theodoros Kolokotronis, hero of the Greek Revolution of 25th of March 1821</p>\n<p>Has an elastic base suitable for most people with circumference from 46cm up to 62cm</p>\n<p>Made in Greece</p>', description_short='<p>This wig is made to resemble Theodoros Kolokotronis, hero of the Greek Revolution of 1821</p>', name='Kolokotronis Hero of 1821 Greek Revolution', link_rewrite='kolokotronis-hero-of-1821-greek-revolution' WHERE id_product=265 AND id_shop=1 AND id_lang=1;
UPDATE `l9n7b_product_lang` SET description='<p>Η περούκα Κολοκοτρώνη είναι φτιαγμένη για να μοιάζει με τα μαλλιά του ήρωα της Ελληνικής Επανάστασης του 1821 Θεόδωρου Κολοκοτρώνη.</p>\n<p>Έχει μεγάλη ελαστική βάση για να ταιριάζει στους περισσότερους ανθρώπους, συγκεκριμένα είναι κατάλληλη για ανθρώπους με περίμετρο κεφαλής από 48 εκ έως 62 εκ.</p>\n<p>Υπάρχει η δυνατότητα κατασκευής κατά παραγγελία σε ειδικές διαστάσεις επιλογής σας.</p>\n<p>Κατασκευάζεται στην Ελλάδα.</p>', description_short='<p>Περούκα Θεόδωρος Κολοκοτρώνης ήρωας της Επανάστασης του 1821.</p>', name='Περούκα Κολοκοτρώνη ήρωα της Επανάστασης του 1821', link_rewrite='-1821' WHERE id_product=265 AND id_shop=1 AND id_lang=2;
UPDATE `l9n7b_product_lang` SET description='<p>This wig is made to resemble Georgios Karaiskakis, hero of the Greek Revolution of 25th of March 1821</p>\n<p>Has an elastic base suitable for most people with circumference from 46cm up to 62cm</p>\n<p>Made in Greece</p>', description_short='<p>This wig is made to resemble Georgios Karaiskakis, hero of the Greek Revolution of 1821</p>', name='Karaiskakis Hero of 1821 Greek Revolution', link_rewrite='kolokotronis-hero-of-1821-greek-revolution' WHERE id_product=266 AND id_shop=1 AND id_lang=1;
UPDATE `l9n7b_product_lang` SET description='<p>Η περούκα Καραϊσκάκη είναι φτιαγμένη για να μοιάζει με τα μαλλιά του ήρωα της Ελληνικής Επανάστασης του 1821 Γεώργιου Καραϊσκάκη.</p>\n<p>Έχει μεγάλη ελαστική βάση για να ταιριάζει στους περισσότερους ανθρώπους, συγκεκριμένα είναι κατάλληλη για ανθρώπους με περίμετρο κεφαλής από 48 εκ έως 62 εκ.</p>\n<p>Υπάρχει η δυνατότητα κατασκευής κατά παραγγελία σε ειδικές διαστάσεις επιλογής σας.</p>\n<p>Κατασκευάζεται στην Ελλάδα.</p>', description_short='<p>Περούκα Γεώργιος Καραϊσκάκης, ήρωας της Ελληνικής Επανάστασης του 1821</p>', name='Περούκα Καραϊσκάκη ήρωα της Επανάστασης του 1821', link_rewrite='-1821' WHERE id_product=266 AND id_shop=1 AND id_lang=2;
